const _falconer = {title: "Falconer", jsx: <><Header full><span>Falconer</span><span>CR 3</span></Header>
<p><strong>Sources</strong> <Link to="/source/npc_codex">NPC Codex pg. 252</Link><br/><strong>XP</strong> 800<br/>Human <Link to="/npcclass/aristocrat">aristocrat</Link> 5<br/>CG Medium humanoid (human)<br/><strong>Init</strong> +1; <strong>Senses</strong> Perception +10</p>
<Header sub>Defense</Header>
<p><strong>AC</strong> 15, touch 11, flat-footed 14 (+4 armor, +1 Dex)<br/><strong>hp</strong> 17 (5d8-5)<br/><strong>Fort</strong> +0, <strong>Ref</strong> +4, <strong>Will</strong> +3</p>
<Header sub>Offense</Header>
<p><strong>Speed</strong> 30 ft.<br/><strong>Melee</strong> mwk short sword +4 (1d6/19-20)<br/><strong>Ranged</strong> mwk light crossbow +5 (1d8/19-20)</p>
<Header sub>Tactics</Header>
<p><strong>During Combat</strong> The aristocrat mounts his horse and flees while shooting his crossbow. He orders his falcon to attack only if his foes seem weak or he is in mortal peril.</p>
<Header sub>Statistics</Header>
<p><strong>Str</strong> 10, <strong>Dex</strong> 12, <strong>Con</strong> 9, <strong>Int</strong> 11, <strong>Wis</strong> 8, <strong>Cha</strong> 14<br/><strong>Base Atk</strong> +3; <strong>CMB</strong> +3; <strong>CMD</strong> 14<br/><strong>Feats</strong> <Link to="/feat/lightning_reflexes">Lightning Reflexes</Link>, <Link to="/feat/mounted_combat">Mounted Combat</Link>, <Link to="/feat/skill_focus">Skill Focus</Link> (Handle Animal, Perception)<br/><strong>Skills</strong> Climb +5, Diplomacy +9, Handle Animal +13, Knowledge (nobility) +7, Perception +10, Profession (falconer) +7, Ride +3, Survival +3<br/><strong>Languages</strong> Common<br/><strong>Combat Gear</strong> potion of <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/eq-weapon/tanglefoot_bag">tanglefoot bag</Link>; <strong>Other Gear</strong> <Link to="/eq-material/mithral">mithral</Link> <Link to="/eq-armor/chain_shirt">chain shirt</Link>, masterwork <Link to="/eq-weapon/light_crossbow">light crossbow</Link> with 20 bolts, masterwork <Link to="/eq-weapon/short_sword">short sword</Link>, <Link to="/eq-misc/signal_whistle">signal whistle</Link>, <Link to="/eq-misc/silver_holy_symbol">silver holy symbol</Link>, trained hawk(equipment-misc/hawk) (worth 40 gp), <Link to="/eq-misc/bit_and_bridle">bit and bridle</Link>, <Link to="/eq-misc/light_horse_combat_trained">light horse (combat trained)</Link>, <Link to="/eq-misc/riding_saddle">riding saddle</Link>, <Link to="/eq-misc/saddlebags">saddlebags</Link>, 360 gp</p>
<Header sub>Description</Header>
<p>The falconer has dedicated his life to training birds of prey-his raptors are his dearest friends. He cares little about courtly life and prefers the company of his noble birds.</p>
</>};
const _frontier_trapper = {title: "Frontier (Trapper)", jsx: <><Header full><span>Frontier (Trapper)</span><span>CR 3</span></Header>
<p><strong>Sources</strong> <Link to="/source/gamemastery_guide">GameMastery Guide pg. 276</Link><br/><strong>XP</strong> 800<br/>Human <Link to="/class/ranger">ranger</Link> 4<br/>N Medium humanoid<br/><strong>Init</strong> +2; <strong>Senses</strong> Perception +7</p>
<Header sub>Defense</Header>
<p><strong>AC</strong> 17, touch 13, flat-footed 14 (+3 armor, +2 Dex, +1 dodge, +1 shield)<br/><strong>hp</strong> 30 (4d10+8)<br/><strong>Fort</strong> +5, <strong>Ref</strong> +6, <strong>Will</strong> +2</p>
<Header sub>Offense</Header>
<p><strong>Speed</strong> 30 ft.<br/><strong>Melee</strong> mwk battleaxe +7 (1d8+2/&times;3) or handaxe +6 (1d6+2/&times;3)<br/><strong>Ranged</strong> mwk composite longbow +7 (1d8+2/&times;3) or throwing axe +6 (1d6+2)<br/><strong>Special Attacks</strong> favored enemy (animals +2)<br/><strong>Ranger Spells Prepared</strong> (CL 1st; concentration +2)<br/><em>1st</em>-<Link to="/spell/charm_animal">charm animal</Link> (DC 12)</p>
<Header sub>Statistics</Header>
<p><strong>Str</strong> 14, <strong>Dex</strong> 15, <strong>Con</strong> 12, <strong>Int</strong> 10, <strong>Wis</strong> 13, <strong>Cha</strong> 10<br/><strong>Base Atk</strong> +4; <strong>CMB</strong> +6; <strong>CMD</strong> 19<br/><strong>Feats</strong> <Link to="/feat/deadly_aim">Deadly Aim</Link>, <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/endurance">Endurance</Link>, <Link to="/feat/mobility">Mobility</Link>, <Link to="/feat/point_blank_shot">Point Blank Shot</Link><br/><strong>Skills</strong> Climb +10, Craft (traps) +9, Handle Animal +6, Heal +8, Perception +7, Profession (trapper) +8, Ride +6, Stealth +8, Survival +8 (+10 to follow tracks), Swim +6<br/><strong>Languages</strong> Common<br/><strong>SQ</strong> <Link to="/ability/favored_terrain">favored terrain</Link> (woods +2), hunter's bond (badger animal companion), track +2, <Link to="/ability/wild_empathy">wild empathy</Link> +4<br/><strong>Combat Gear</strong> <Link to="/eq-poison/black_adder_venom">black adder venom</Link> (1 dose), scrolls of <Link to="/spell/cure_light_wounds">cure light wounds</Link> (2), scrolls of <Link to="/spell/speak_with_animals">speak with animals</Link> (2); <strong>Other Gear</strong> masterwork <Link to="/eq-armor/studded_leather">studded leather</Link>, masterwork <Link to="/eq-armor/buckler">buckler</Link>, masterwork <Link to="/eq-weapon/battleaxe">battleaxe</Link>, masterwork <Link to="/eq-weapon/composite_longbow">composite longbow</Link> (+1 Str) with 20 arrows, <Link to="/eq-weapon/throwing_axe">throwing axes</Link> (2), <Link to="/eq-misc/climbers_kit">climber's kit</Link>, <Link to="/eq-misc/healers_kit">healer's kit</Link>, masterwork trapmaking tools<br/><strong>Boon</strong> Trappers can provide food for the PCs for 1 week and can tell them secrets of the wild lands where they live, granting a +2 circumstance bonus on Survival checks within a 20-mile radius.</p>
<Header sub>Description</Header>
<p>Trappers are roving hunters who wander the woods. They take any animal they can safely hunt or trap, but they are best known as the heart of the fur trade, making a variety of handcrafted but deadly effective traps to catch the unwary beasts of the forest. Trappers could be used as royal game wardens, as scouts, or as hunters for a nomadic tribe.</p>
<p>Trappers are typically loners but will sometimes pair up with another trapper (CR 5), a monster hunter (CR 6), or a beast master (CR 7) for companionship.</p>
</>};
const _harbinger_disciple = {title: "Harbinger Disciple", jsx: <><Header full><span>Harbinger Disciple</span><span>CR 3</span></Header>
<p><strong>Sources</strong> <Link to="/source/inner_sea_npc_codex">Inner Sea NPC Codex pg. 28</Link><br/><strong>XP</strong> 800<br/>Human <Link to="/class/oracle">oracle</Link> 4<br/>CN Medium humanoid (human)<br/><strong>Init</strong> +1; <strong>Senses</strong> Perception -1</p>
<Header sub>Defense</Header>
<p><strong>AC</strong> 13, touch 11, flat-footed 12 (+2 armor, +1 Dex)<br/><strong>hp</strong> 29 (4d8+8)<br/><strong>Fort</strong> +6, <strong>Ref</strong> +3, <strong>Will</strong> +4</p>
<Header sub>Offense</Header>
<p><strong>Speed</strong> 30 ft.<br/><strong>Melee</strong> mwk light mace +4 (1d6)<br/><strong>Ranged</strong> dagger +4 (1d4/19-20)<br/><strong>Oracle Spells Known</strong> (CL 4th; concentration +8)<br/><em>2nd (4/day)</em>-<Link to="/spell/enthrall">enthrall</Link> (DC 17), <Link to="/spell/gentle_repose">gentle repose</Link>, <Link to="/spell/inflict_moderate_wounds">inflict moderate wounds</Link> (DC 16)<br/><em>1st (7/day)</em>-<Link to="/spell/cause_fear">cause fear</Link> (DC 15), <Link to="/spell/command">command</Link> (DC 16), <Link to="/spell/doom">doom</Link> (DC 15), <Link to="/spell/inflict_light_wounds">inflict light wounds</Link> (DC 15), <Link to="/spell/memory_lapse">memory lapse</Link> (DC 18)<br/><em>0 (at will)</em>-<Link to="/spell/bleed">bleed</Link> (DC 14), <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/guidance">guidance</Link>, <Link to="/spell/light">light</Link>, <Link to="/spell/read_magic">read magic</Link>, <Link to="/spell/virtue">virtue</Link><br/><strong>Mystery</strong> <Link to="/mystery/time">time</Link></p>
<Header sub>Statistics</Header>
<p><strong>Str</strong> 10, <strong>Dex</strong> 13, <strong>Con</strong> 14, <strong>Int</strong> 12, <strong>Wis</strong> 8, <strong>Cha</strong> 18<br/><strong>Base Atk</strong> +3; <strong>CMB</strong> +3; <strong>CMD</strong> 14<br/><strong>Feats</strong> <Link to="/feat/deceitful">Deceitful</Link>, <Link to="/feat/great_fortitude">Great Fortitude</Link>, <Link to="/feat/spell_focus">Spell Focus</Link> (enchantment)<br/><strong>Skills</strong> Bluff +10, Disable Device +5, Disguise +6, Intimidate +8, Knowledge (history) +8, Knowledge (religion) +6, Perform (oratory) +8, Sense Motive +4, Use Magic Device +8<br/><strong>Languages</strong> Aklo, Common, Infernal<br/><strong>SQ</strong> oracle's curse (tongues), revelations (erase from time, momentary glimpse)<br/><strong>Combat Gear</strong> potion of <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, scroll of <Link to="/spell/augury">augury</Link>, wand of <Link to="/spell/shield_of_faith">shield of faith</Link> (22 charges), <Link to="/eq-misc/smokestick">smokestick</Link>, <Link to="/eq-weapon/thunderstone">thunderstone</Link>; <strong>Other Gear</strong> <Link to="/eq-armor/leather_armor">leather armor</Link>, <Link to="/eq-weapon/dagger">dagger</Link>, mwk <Link to="/eq-weapon/light_mace">light mace</Link>, Book of 1,000 Whispers, <Link to="/magic-wondrous/cloak_of_resistance_1">cloak of resistance +1</Link>, 233 gp</p>
<Header sub>Description</Header>
<p>It's widely accepted that prophecy has been unreliable since the death of Aroden, so much so that the current era is known as the Age of Lost Omens. Not all see the failure of prophecy as so certain, however; most notable among them are the Harbingers of Fate. This Absalom-based secret society may seem like a band of lunatics unable to cope with their philosophy being negated by the passing of time, but in fact they pose a real threat to the safety of the City at the Center of the World. After all, nothing is more important to the Harbingers of Fate than restoring prophecy, even if doing so causes the deaths of thousands of innocents.</p>
<p>Founded in 4648 AR by Lord Garron, an exiled Chelish noble living in Absalom, the Harbingers believe that bringing about the prophesies foretold the mysterious Book of 1,000 Whispers will put history back on its proper course and usher in the promised Age of Glory, perhaps even returning of Aroden himself to the world. But like all other forms of soothsaying, the writings in the Book of 1,000 Whispers-accurate up until 4606 AR-lost all reliability in predicting the future after Aroden's demise. Lord Garron desperately (and fruitlessly) tried to fulfill these prophecies for the remainder of his life, before dying in one such failed attempt. His daughter Lady Arodeth continues his work today and leads the small but fanatical group of disciples of the Book of 1,000 Whispers in Absalom. The Harbingers' methods have been growing more and more desperate in recent years, as the book's final pronouncements are said to occur in 4714 AR; so far, none of them have come true.</p>
</>};
const _investigator_wizard = {title: "Investigator Wizard", jsx: <><Header full><span>Investigator Wizard</span><span>CR 3</span></Header>
<p><strong>Sources</strong> <Link to="/source/npc_codex">NPC Codex pg. 179</Link><br/><strong>XP</strong> 800<br/>Human diviner 4<br/>LN Medium humanoid (human)<br/><strong>Init</strong> +8; <strong>Senses</strong> Perception +5</p>
<Header sub>Defense</Header>
<p><strong>AC</strong> 18, touch 14, flat-footed 15 (+4 armor, +1 deflection, +2 Dex, +1 dodge)<br/><strong>hp</strong> 22 (4d6+6)<br/><strong>Fort</strong> +2, <strong>Ref</strong> +3, <strong>Will</strong> +5</p>
<Header sub>Offense</Header>
<p><strong>Speed</strong> 30 ft.<br/><strong>Melee</strong> club +1 (1d6-1)<br/><strong>Ranged</strong> light crossbow +4 (1d8/19-20)<br/><strong>Spell-Like Abilities</strong> (CL 4th; concentration +8)<br/><em>7/day</em>-diviner's fortune (+2)<br/><strong>Diviner Spells Prepared</strong> (CL 4th; concentration +8)<br/><em>2nd</em>-<Link to="/spell/cats_grace">cat's grace</Link>, detect thoughts (DC 16), <Link to="/spell/web">web</Link> (2, DC 16)<br/><em>1st</em>-<Link to="/spell/comprehend_languages">comprehend languages</Link>, <Link to="/spell/feather_fall">feather fall</Link>, <Link to="/spell/mage_armor">mage armor</Link>, <Link to="/spell/magic_missile">magic missile</Link> (2)<br/><em>0 (at will)</em>-<Link to="/spell/dancing_lights">dancing lights</Link>, <Link to="/spell/detect_magic">detect magic</Link>, <Link to="/spell/detect_poison">detect poison</Link>, <Link to="/spell/message">message</Link><br/><strong>Opposition Schools</strong> illusion, necromancy</p>
<Header sub>Tactics</Header>
<p><strong>Before Combat</strong> The wizard casts mage armor.<br/><strong>During Combat</strong> If surprised, the wizard uses forewarned to cast cat's grace in the surprise round. He uses web, color spray, or sleep against targets he intends to capture.<br/><strong>Base Statistics</strong> Without mage armor, the wizard's statistics are <strong>AC</strong> 14, touch 14, flat-footed 11.</p>
<Header sub>Statistics</Header>
<p><strong>Str</strong> 8, <strong>Dex</strong> 14, <strong>Con</strong> 13, <strong>Int</strong> 18, <strong>Wis</strong> 12, <strong>Cha</strong> 10<br/><strong>Base Atk</strong> +2; <strong>CMB</strong> +1; <strong>CMD</strong> 15<br/><strong>Feats</strong> <Link to="/feat/combat_casting">Combat Casting</Link>, <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/improved_initiative">Improved Initiative</Link>, <Link to="/feat/scribe_scroll">Scribe Scroll</Link><br/><strong>Skills</strong> Diplomacy +4, Intimidate +4, Knowledge (arcana, local) +10, Knowledge (geography, history, nobility, religion) +8, Perception +5, Sense Motive +5, Spellcraft +11<br/><strong>Languages</strong> Common, Draconic, Dwarven, Elven, Orc<br/><strong>SQ</strong> arcane bond (ring of protection +1), forewarned<br/><strong>Combat Gear</strong> potion of <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, scroll of <Link to="/spell/detect_thoughts">detect thoughts</Link>, scroll of <Link to="/spell/knock">knock</Link>, scroll of <Link to="/spell/locate_object">locate object</Link>, scrolls of <Link to="/spell/sleep">sleep</Link> (2), wand of <Link to="/spell/color_spray">color spray</Link> (20 charges); <strong>Other Gear</strong> <Link to="/eq-weapon/club">club</Link>, <Link to="/eq-weapon/light_crossbow">light crossbow</Link> with 20 bolts, <Link to="/magic-ring/ring_of_protection_1">ring of protection +1</Link>, <Link to="/eq-misc/manacles">manacles</Link>, <Link to="/eq-misc/spellbook">spellbook</Link>, 125 gp</p>
<Header sub>Description</Header>
<p>The investigator mage works with city guards to investigate crimes.</p>
</>};
const _lastwall_border_scout = {title: "Lastwall Border Scout", jsx: <><Header full><span>Lastwall Border Scout</span><span>CR 3</span></Header>
<p><strong>Sources</strong> <Link to="/source/castles_of_the_inner_sea">Castles of the Inner Sea pg. 10</Link><br/><strong>XP</strong> 800<br/>Human <Link to="/class/ranger">ranger</Link> 4<br/>LG Medium humanoid (human)<br/><strong>Init</strong> +6; <strong>Senses</strong> Perception +8</p>
<Header sub>Defense</Header>
<p><strong>AC</strong> 16, touch 12, flat-footed 14 (+3 armor, +2 Dex, +1 shield)<br/><strong>hp</strong> 38 (4d10+12)<br/><strong>Fort</strong> +7, <strong>Ref</strong> +6, <strong>Will</strong> +2</p>
<Header sub>Offense</Header>
<p><strong>Speed</strong> 30 ft.<br/><strong>Melee</strong> mwk longsword +7 (1d8+3/19-20)<br/><strong>Ranged</strong> mwk composite longbow +8 (1d8+2/&times;3)<br/><strong>Special Attacks</strong> favored enemy (orcs +2)<br/><strong>Ranger Spells Prepared</strong> (CL 1st; concentration +2)<br/><em>1st</em>-<Link to="/spell/longstrider">longstrider</Link></p>
<Header sub>Tactics</Header>
<p><strong>During Combat</strong> While scouting at night, a Lastwall border scout is sure to imbibe her potion of darkvision and stay close to her allies. In combat, she uses her bow to strike down foes from a great distance, taking to melee only as a last resort. Smokesticks allow the rangers to send signals to one another while split up, and alchemist's fire ensures that they can make short work of any trolls or other nasty foes they encounter.<br/><strong>Morale</strong> If pressed by a force they cannot hope to defeat alone, Lastwall border scouts do their best to evade and lose any enemies following them before returning to Castle Everstand or another nearby Lastwall border fort.</p>
<Header sub>Statistics</Header>
<p><strong>Str</strong> 15, <strong>Dex</strong> 14, <strong>Con</strong> 16, <strong>Int</strong> 10, <strong>Wis</strong> 12, <strong>Cha</strong> 8<br/><strong>Base Atk</strong> +4; <strong>CMB</strong> +6; <strong>CMD</strong> 18<br/><strong>Feats</strong> <Link to="/feat/deadly_aim">Deadly Aim</Link>, <Link to="/feat/endurance">Endurance</Link>, <Link to="/feat/far_shot">Far Shot</Link>, <Link to="/feat/improved_initiative">Improved Initiative</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link> (composite longbow)<br/><strong>Skills</strong> Climb +8, Handle Animal +6, Heal +8, Intimidate +6, Knowledge (geography) +7, Perception +8, Stealth +8, Survival +8<br/><strong>Languages</strong> Common<br/><strong>SQ</strong> <Link to="/ability/favored_terrain">favored terrain</Link> (plains +2), hunter's bond (companions), track +2, <Link to="/ability/wild_empathy">wild empathy</Link> +3<br/><strong>Combat Gear</strong> potion of <Link to="/spell/darkvision">darkvision</Link>, +1 orc-<Link to="/magic-enh/bane">bane</Link> arrows (5), <Link to="/eq-weapon/alchemists_fire">alchemist's fire</Link> (2), <Link to="/eq-misc/antitoxin">antitoxin</Link>, <Link to="/eq-misc/smokestick">smokesticks</Link> (2); <strong>Other Gear</strong> mwk <Link to="/eq-armor/studded_leather">studded leather</Link>, <Link to="/eq-armor/light_wooden_shield">light wooden shield</Link>, mwk <Link to="/eq-weapon/composite_longbow">composite longbow</Link> (+2 Str) with 20 arrows, mwk <Link to="/eq-weapon/longsword">longsword</Link>, 49 gp</p>
<Header sub>Description</Header>
<p>Travelers roaming the plains between Lastwall and Belkzen may accidentally encounter scouts from Everstand sent to watch the borderlands, though such border rangers are masters of stealth and are rarely seen unless they wish to be.</p>
</>};
const _lumber_consortium_enforcer = {title: "Lumber Consortium Enforcer", jsx: <><p><em>This beefy human brawler has the bearing of a thug.</em></p>
<Header full><span>Lumber Consortium Enforcer</span><span>CR 3</span></Header>
<p><strong>Sources</strong> <Link to="/source/andoran_birthplace_of_freedom">Andoran, Birthplace of Freedom pg. 57</Link><br/><strong>XP</strong> 800<br/>Human <Link to="/class/brawler">brawler</Link> 4<br/>NE Medium humanoid (human)<br/><strong>Init</strong> +1; <strong>Senses</strong> Perception +5</p>
<Header sub>Defense</Header>
<p><strong>AC</strong> 15, touch 11, flat-footed 14 (+4 armor, +1 Dex)<br/><strong>hp</strong> 33 (4d10+11)<br/><strong>Fort</strong> +7, <strong>Ref</strong> +6, <strong>Will</strong> +3</p>
<Header sub>Offense</Header>
<p><strong>Speed</strong> 30 ft.<br/><strong>Melee</strong> mwk longspear +9 (1d8+6/&times;3) or handaxe +8 (1d6+4/&times;3) or unarmed strike +8 (1d8+4)<br/><strong>Ranged</strong> javelin +5 (1d6+4)<br/><strong>Special Attacks</strong> knockout (DC 16) 1/day, martial flexibility 5/day</p>
<Header sub>Statistics</Header>
<p><strong>Str</strong> 18, <strong>Dex</strong> 13, <strong>Con</strong> 14, <strong>Int</strong> 8, <strong>Wis</strong> 12, <strong>Cha</strong> 10<br/><strong>Base Atk</strong> +4; <strong>CMB</strong> +8 (+9 trip); <strong>CMD</strong> 19 (20 vs. trip)<br/><strong>Feats</strong> <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/enforcer">Enforcer</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/intimidating_prowess">Intimidating Prowess</Link>, <Link to="/feat/power_attack">Power Attack</Link><br/><strong>Skills</strong> Acrobatics +7, Climb +7, Intimidate +11, Perception +5, Profession (woodcutter) +5, Ride +4, Sense Motive +5, Stealth +4, Swim +7<br/><strong>Languages</strong> Common<br/><strong>SQ</strong> brawler's cunning, martial training</p>
<Header sub>Ecology</Header>
<p><strong>Environment</strong> any forest or urban (especially Darkmoon Vale)<br/><strong>Organization</strong> solitary, pair, or gang (3-12)<br/><strong>Treasure</strong> <Link to="/rule/npc_gear">NPC gear</Link> (mwk <Link to="/eq-armor/chain_shirt">chain shirt</Link>, mwk <Link to="/eq-weapon/longspear">longspear</Link>, <Link to="/eq-weapon/handaxe">handaxe</Link>, <Link to="/eq-weapon/javelin">javelins</Link> (3), <Link to="/magic-wondrous/cloak_of_resistance_1">cloak of resistance +1</Link>, other treasure)</p>
<Header sub>Description</Header>
<p>The Lumber Consortium maintains its monopoly on hardwood imports, exports, and manufacturing in much of Andoran by means of political manipulation and influence (both legal and otherwise), but employs gangs of enforcers to maintain its power and authority on a local level. Some Lumber Consortium enforcers are disaffected mercenaries or soldiers from elsewhere who have been recruited by the consortium to keep order in their company mill towns. Others have risen through the ranks of the company, beginning as simple roughnecks on the logging crews but showing an aptitude for pushing others around and informing on those they see as slackers to the company overseers.</p>
<p>Lumber Consortium enforcers serve a dual role as overseers for the company that manage works crews while nominally offering skilled protection from any threats the forest might offer. In reality, enforcers' responsibilities within the company vary wildly based on the talent of the individuals and the whims of their overseers. Though not necessarily well schooled, some enforcers are selected for their cunning, intuition, and ability to motivate underlings by finding methods that keep people in line.</p>
<p>Since the Lumber Consortium considers itself the de facto authority in the lands it claims, these enforcers often take on the role of a police force. While a few do their best to maintain order and pursue justice, others spend more time spying on the populace and arresting people for "interfering with company business." Those living in areas controlled by the consortium are often subjected to threats, intimidation, and even beatings. Occasionally, the enforcers' strong-arm tactics do elicit useful information about people working outside the company's control, but for many enforcers the bullying is its own reward, and a means to maintain a climate of fear and control.</p>
</>};
const _murderous_halfling = {title: "Murderous Halfling", jsx: <><Header full><span>Murderous Halfling</span><span>CR 3</span></Header>
<p><strong>Sources</strong> <Link to="/source/npc_codex">NPC Codex pg. 81</Link><br/><strong>XP</strong> 800<br/>Halfling <Link to="/class/fighter">fighter</Link> 4<br/>CE Small humanoid (halfling)<br/><strong>Init</strong> +4; <strong>Senses</strong> Perception +6</p>
<Header sub>Defense</Header>
<p><strong>AC</strong> 20, touch 15, flat-footed 16 (+5 armor, +4 Dex, +1 size)<br/><strong>hp</strong> 30 (4d10+4)<br/><strong>Fort</strong> +6, <strong>Ref</strong> +6, <strong>Will</strong> +2; +3 vs. fear<br/><strong>Defensive Abilities</strong> bravery +1</p>
<Header sub>Offense</Header>
<p><strong>Speed</strong> 20 ft.<br/><strong>Melee</strong> mwk dagger +9 (1d3+3/19-20), mwk dagger +9 (1d3+2/19-20)<br/><strong>Ranged</strong> dagger +10 (1d3+3/19-20)</p>
<Header sub>Tactics</Header>
<p><strong>During Combat</strong> The fighter hurls daggers until her foes close with her. In melee, she fights defensively (and gains a +3 dodge bonus from her ranks in Acrobatics). She keeps her feather token in reserve for dangerous spellcasters or when battle turns against her.</p>
<Header sub>Statistics</Header>
<p><strong>Str</strong> 12, <strong>Dex</strong> 18, <strong>Con</strong> 12, <strong>Int</strong> 13, <strong>Wis</strong> 10, <strong>Cha</strong> 10<br/><strong>Base Atk</strong> +4; <strong>CMB</strong> +4; <strong>CMD</strong> 18<br/><strong>Feats</strong> <Link to="/feat/deadly_aim">Deadly Aim</Link>, <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link>, <Link to="/feat/weapon_finesse">Weapon Finesse</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link> (dagger), <Link to="/feat/weapon_specialization">Weapon Specialization</Link> (dagger)<br/><strong>Skills</strong> Acrobatics +10 (+6 when jumping), Bluff +4, Climb +3, Perception +6, Sleight of Hand +5, Stealth +11<br/><strong>Languages</strong> Common, Goblin, Halfling<br/><strong>SQ</strong> armor training 1<br/><strong>Combat Gear</strong> <Link to="/magic-wondrous/feather_token_whip">feather token (whip)</Link>, flask of <Link to="/eq-weapon/acid">acid</Link>; <strong>Other Gear</strong> +1 <Link to="/eq-armor/chain_shirt">chain shirt</Link>, <Link to="/eq-weapon/dagger">daggers</Link> (6), masterwork daggers (2), 24 gp</p>
<Header sub>Description</Header>
<p>Small, sly, and seemingly innocuous, evil halflings make perfect murderers.</p>
<h3 id="npc-murderous_halfling-lisanne-jelansil">Lisanne Jelansil</h3>
<p>At first, Lisanne saved her murderous attentions for those who slighted her in some small fashion. Now, she revels in death for death's sake rather than for vengeance only. Her reputation has grown with her crimes, and she increasingly plies her skills for pay as well as pleasure.</p>
</>};
